function fmtMoney(v) {
  if (v == null) return '—';
  return (
    '$' +
    v.toLocaleString('en-US', {
      minimumFractionDigits: 2,
      maximumFractionDigits: 2,
    })
  );
}
function fmtDelta(v) {
  if (v == null) return '—';
  const abs = Math.abs(v).toLocaleString('en-US', {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2,
  });
  return (v >= 0 ? '+' : '-') + '$' + abs;
}
function fmtPct(v) {
  if (v == null) return '—';
  return (v >= 0 ? '+' : '') + v.toFixed(1) + '%';
}
function deltaColor(v) {
  if (v == null) return '#7a8a9a';
  if (v > 0) return '#3ecf8e';
  if (v < 0) return '#f66';
  return '#7a8a9a';
}

// ── DROPDOWN ─────────────────────────────────────────────────────
function MultiSelect({ label, options, selected, onChange }) {
  const [open, setOpen] = useState(false);
  const allSel = selected.length === options.length;
  const toggle = (v) =>
    onChange(
      selected.includes(v) ? selected.filter((x) => x !== v) : [...selected, v]
    );
  const toggleAll = () => onChange(allSel ? [] : [...options]);
  const btnStyle = {
    background: '#0f1923',
    border: '1px solid #2a3a4a',
    color: '#c8d8e8',
    padding: '7px 12px',
    borderRadius: 6,
    cursor: 'pointer',
    fontSize: 12,
    display: 'flex',
    alignItems: 'center',
    gap: 6,
    width: '100%',
    justifyContent: 'space-between',
    fontFamily: "'DM Mono', monospace",
  };
  return (
    <div style={{ position: 'relative', minWidth: 160 }}>
      <button onClick={() => setOpen((o) => !o)} style={btnStyle}>
        <span>
          {label}:{' '}
          {allSel
            ? 'ALL'
            : selected.length === 0
            ? 'NONE'
            : selected.length + ' sel'}
        </span>
        <span style={{ fontSize: 9, opacity: 0.6 }}>▼</span>
      </button>
      {open && (
        <div
          style={{
            position: 'absolute',
            top: '110%',
            left: 0,
            zIndex: 100,
            background: '#0f1923',
            border: '1px solid #2a3a4a',
            borderRadius: 6,
            minWidth: 200,
            maxHeight: 280,
            overflowY: 'auto',
            boxShadow: '0 8px 32px rgba(0,0,0,0.6)',
          }}
        >
          <div
            onClick={toggleAll}
            style={{
              padding: '8px 12px',
              cursor: 'pointer',
              fontSize: 11,
              color: '#7aa8c8',
              borderBottom: '1px solid #1e2e3e',
              fontFamily: "'DM Mono', monospace",
              background: allSel ? '#1a2a3a' : 'transparent',
            }}
          >
            {allSel ? '✓ ' : '  '}SELECT ALL
          </div>
          {options.map((opt) => (
            <div
              key={opt}
              onClick={() => toggle(opt)}
              style={{
                padding: '7px 12px',
                cursor: 'pointer',
                fontSize: 11,
                color: '#c8d8e8',
                background: selected.includes(opt) ? '#1a2a3a' : 'transparent',
                fontFamily: "'DM Mono', monospace",
                borderBottom: '1px solid #0d1820',
              }}
            >
              {selected.includes(opt) ? '✓ ' : '  '}
              {opt}
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

function KpiTile({ label, value, accent, divider }) {
  return (
    <div
      style={{
        flex: '1 0 110px',
        padding: '14px 18px',
        borderRight: '1px solid #1e3040',
        background: '#080f18',
        borderLeft: divider ? '2px solid #2a2a5a' : 'none',
      }}
    >
      <div
        style={{
          fontSize: 9,
          letterSpacing: 2,
          color: '#3a6a8a',
          marginBottom: 4,
        }}
      >
        {label}
      </div>
      <div style={{ fontSize: 15, fontWeight: 500, color: accent }}>
        {value}
      </div>
    </div>
  );
}

function PctBadge({ pct, large }) {
  const bg =
    pct == null
      ? 'transparent'
      : pct > 0
      ? 'rgba(62,207,142,0.12)'
      : pct < 0
      ? 'rgba(255,102,102,0.12)'
      : 'transparent';
  return (
    <span
      style={{
        background: bg,
        color: deltaColor(pct),
        padding: large ? '3px 7px' : '2px 6px',
        borderRadius: 3,
        fontSize: large ? 11 : 10,
      }}
    >
      {fmtPct(pct)}
    </span>
  );
}

function SectionHeader({ title, sub, badge }) {
  return (
    <div
      style={{
        padding: '18px 28px 0',
        display: 'flex',
        alignItems: 'baseline',
        justifyContent: 'space-between',
      }}
    >
      <div>
        <div
          style={{
            fontSize: 9,
            letterSpacing: 3,
            color: '#3a6a8a',
            marginBottom: 3,
          }}
        >
          {sub}
        </div>
        <div
          style={{
            fontSize: 16,
            fontFamily: "'Space Grotesk', sans-serif",
            fontWeight: 700,
            color: '#e8f4ff',
          }}
        >
          {title}
        </div>
      </div>
      {badge && <div style={{ fontSize: 10, color: '#3a6a8a' }}>{badge}</div>}
    </div>
  );
}

function DataTable({ cols, rows, totalsRow, defaultSort, firstColLeft }) {
  const [sortCol, setSortCol] = useState(defaultSort || 'tw');
  const [sortDir, setSortDir] = useState('desc');
  const handleSort = (col) => {
    if (sortCol === col) setSortDir((d) => (d === 'asc' ? 'desc' : 'asc'));
    else {
      setSortCol(col);
      setSortDir('desc');
    }
  };
  const sorted = useMemo(() => {
    return [...rows].sort((a, b) => {
      const av = a[sortCol] != null ? a[sortCol] : -Infinity;
      const bv = b[sortCol] != null ? b[sortCol] : -Infinity;
      return sortDir === 'asc' ? av - bv : bv - av;
    });
  }, [rows, sortCol, sortDir]);

  const thBase = {
    fontSize: 10,
    letterSpacing: 1.5,
    color: '#5a8aaa',
    cursor: 'pointer',
    userSelect: 'none',
    whiteSpace: 'nowrap',
    borderBottom: '1px solid #1e3040',
    fontFamily: "'DM Mono', monospace",
    padding: '10px 14px',
  };
  return (
    <div style={{ overflowX: 'auto' }}>
      <table style={{ width: '100%', borderCollapse: 'collapse' }}>
        <thead>
          <tr>
            {cols.map((c, ci) => (
              <th
                key={c.col}
                onClick={() => handleSort(c.col)}
                style={Object.assign({}, thBase, {
                  textAlign: firstColLeft && ci === 0 ? 'left' : 'right',
                  background: sortCol === c.col ? '#0d1e2e' : 'transparent',
                  borderLeft: c.divider ? '2px solid #1e2a4a' : 'none',
                })}
              >
                {c.label}
                {sortCol === c.col ? (sortDir === 'asc' ? ' ↑' : ' ↓') : ''}
              </th>
            ))}
          </tr>
        </thead>
        <tbody>
          {sorted.map((row, ri) => {
            const bg = ri % 2 === 0 ? '#080f18' : '#060e17';
            return (
              <tr key={row._key || ri}>
                {cols.map((c, ci) => {
                  const v = row[c.col];
                  const align = firstColLeft && ci === 0 ? 'left' : 'right';
                  const cellBase = {
                    padding: '8px 14px',
                    textAlign: align,
                    fontSize: 11,
                    borderBottom: '1px solid #0d1820',
                    background: bg,
                    borderLeft: c.divider ? '2px solid #1e2a4a' : 'none',
                    fontWeight: c.bold ? 500 : 'normal',
                  };
                  if (c.type === 'pct') {
                    return (
                      <td key={c.col} style={cellBase}>
                        <PctBadge pct={v} />
                      </td>
                    );
                  }
                  let txt = v,
                    color = '#c8d8e8';
                  if (c.type === 'label') {
                    txt = v;
                    color = c.color || '#c8d8e8';
                  }
                  if (c.type === 'money') {
                    txt = fmtMoney(v);
                    color = c.color || '#c8d8e8';
                  }
                  if (c.type === 'delta') {
                    txt = fmtDelta(v);
                    color = deltaColor(v);
                  }
                  return (
                    <td
                      key={c.col}
                      style={Object.assign({}, cellBase, { color })}
                    >
                      {txt}
                    </td>
                  );
                })}
              </tr>
            );
          })}
          {totalsRow && (
            <tr>
              {cols.map((c, ci) => {
                const v = totalsRow[c.col];
                const align = firstColLeft && ci === 0 ? 'left' : 'right';
                const cellBase = {
                  padding: '11px 14px',
                  textAlign: align,
                  fontSize: 12,
                  fontWeight: 700,
                  background: '#0d1e2e',
                  borderLeft: c.divider ? '2px solid #1e2a4a' : 'none',
                };
                if (c.type === 'pct') {
                  return (
                    <td key={c.col} style={cellBase}>
                      <PctBadge pct={v} large />
                    </td>
                  );
                }
                let txt = v,
                  color = '#c8e8ff';
                if (c.type === 'label') {
                  txt = v || 'TOTAL';
                  color = '#7acfff';
                }
                if (c.type === 'money') {
                  txt = fmtMoney(v);
                  color = c.color || '#c8e8ff';
                }
                if (c.type === 'delta') {
                  txt = fmtDelta(v);
                  color = deltaColor(v);
                }
                return (
                  <td
                    key={c.col}
                    style={Object.assign({}, cellBase, { color })}
                  >
                    {txt}
                  </td>
                );
              })}
            </tr>
          )}
        </tbody>
      </table>
    </div>
  );
}

// ── MAIN ──────────────────────────────────────────────────────────
export default function SalesReport() {
  const [selectedWeeks, setSelectedWeeks] = useState([
    ALL_WEEKS[ALL_WEEKS.length - 1],
  ]);
  const [selectedDCs, setSelectedDCs] = useState([...ALL_DCS]);
  const [selectedProducts, setSelectedProducts] = useState([...ALL_PRODUCTS]);
  const [selectedStores, setSelectedStores] = useState(
    Object.values(DC_STORES).flat()
  );
  const [activeTab, setActiveTab] = useState('wow');

  const toggleWeek = (w) => {
    setSelectedWeeks((prev) =>
      prev.includes(w)
        ? prev.length > 1
          ? prev.filter((x) => x !== w)
          : prev
        : [...prev, w].sort()
    );
  };

  const prevWeek = useMemo(() => {
    const minSel = Math.min(...selectedWeeks);
    const idx = ALL_WEEKS.indexOf(minSel);
    return idx > 0 ? ALL_WEEKS[idx - 1] : null;
  }, [selectedWeeks]);

  const lyWeeks = useMemo(
    () => selectedWeeks.map((w) => 202500 + (w % 100)),
    [selectedWeeks]
  );

  const availableStores = useMemo(() => {
    const s = new Set();
    selectedDCs.forEach((dc) => (DC_STORES[dc] || []).forEach((v) => s.add(v)));
    return [...s].sort((a, b) => a - b);
  }, [selectedDCs]);

  const handleDCChange = (newDCs) => {
    setSelectedDCs(newDCs);
    const s = new Set();
    newDCs.forEach((dc) => (DC_STORES[dc] || []).forEach((v) => s.add(v)));
    setSelectedStores([...s].sort((a, b) => a - b));
  };

  const storeTodc = useMemo(() => {
    const m = {};
    Object.keys(DC_STORES).forEach((dc) => {
      DC_STORES[dc].forEach((s) => {
        m[s] = dc;
      });
    });
    return m;
  }, []);

  // ── SINGLE SHARED AGGREGATION — all filters applied at once ──
  const agg = useMemo(() => {
    const dcSet = new Set(selectedDCs);
    const prodSet = new Set(selectedProducts);
    const storeSet = new Set(
      selectedStores.filter((s) => availableStores.includes(s))
    );
    const weekSet = new Set(selectedWeeks);
    const lySet = new Set(lyWeeks);
    const prevSet = prevWeek ? new Set([prevWeek]) : new Set();

    // FY26
    const prod_tw = {},
      prod_lw = {};
    const store_tw = {},
      store_lw = {};
    const dc_tw = {},
      dc_lw = {};
    const ytd_prod26 = {},
      ytd_dc26 = {},
      ytd_store26 = {};

    DATA26.forEach((r) => {
      if (!dcSet.has(r.dc) || !prodSet.has(r.product) || !storeSet.has(r.store))
        return;
      // WoW
      if (weekSet.has(r.fw)) {
        prod_tw[r.product] = (prod_tw[r.product] || 0) + r.sales;
        store_tw[r.dc + '__' + r.store] =
          (store_tw[r.dc + '__' + r.store] || 0) + r.sales;
        dc_tw[r.dc] = (dc_tw[r.dc] || 0) + r.sales;
      }
      if (prevSet.has(r.fw)) {
        prod_lw[r.product] = (prod_lw[r.product] || 0) + r.sales;
        store_lw[r.dc + '__' + r.store] =
          (store_lw[r.dc + '__' + r.store] || 0) + r.sales;
        dc_lw[r.dc] = (dc_lw[r.dc] || 0) + r.sales;
      }
      // YTD (all weeks in DATA26)
      ytd_prod26[r.product] = (ytd_prod26[r.product] || 0) + r.sales;
      ytd_dc26[r.dc] = (ytd_dc26[r.dc] || 0) + r.sales;
      ytd_store26[r.dc + '__' + r.store] =
        (ytd_store26[r.dc + '__' + r.store] || 0) + r.sales;
    });

    // FY25
    const prod_ly = {},
      store_ly = {},
      dc_ly = {};
    const ytd_prod25 = {},
      ytd_dc25 = {},
      ytd_store25 = {};

    DATA25.forEach((r) => {
      if (!dcSet.has(r.dc) || !prodSet.has(r.product) || !storeSet.has(r.store))
        return;
      if (lySet.has(r.fw)) {
        prod_ly[r.product] = (prod_ly[r.product] || 0) + r.sales;
        store_ly[r.dc + '__' + r.store] =
          (store_ly[r.dc + '__' + r.store] || 0) + r.sales;
        dc_ly[r.dc] = (dc_ly[r.dc] || 0) + r.sales;
      }
      ytd_prod25[r.product] = (ytd_prod25[r.product] || 0) + r.sales;
      ytd_dc25[r.dc] = (ytd_dc25[r.dc] || 0) + r.sales;
      ytd_store25[r.dc + '__' + r.store] =
        (ytd_store25[r.dc + '__' + r.store] || 0) + r.sales;
    });

    return {
      prod_tw,
      prod_lw,
      prod_ly,
      store_tw,
      store_lw,
      store_ly,
      dc_tw,
      dc_lw,
      dc_ly,
      ytd_prod26,
      ytd_prod25,
      ytd_dc26,
      ytd_dc25,
      ytd_store26,
      ytd_store25,
    };
  }, [
    selectedWeeks,
    prevWeek,
    lyWeeks,
    selectedDCs,
    selectedProducts,
    selectedStores,
    availableStores,
  ]);

  // ── WoW PRODUCT ──
  const wowProdRows = useMemo(() => {
    return selectedProducts
      .map((p) => {
        const tw = agg.prod_tw[p] || 0,
          lw = agg.prod_lw[p] || 0,
          ly = agg.prod_ly[p] || 0;
        return {
          _key: p,
          product: p,
          tw,
          lw,
          ly,
          delta: tw - lw,
          pct: lw ? ((tw - lw) / lw) * 100 : null,
          yoy_delta: tw - ly,
          yoy_pct: ly ? ((tw - ly) / ly) * 100 : null,
        };
      })
      .filter((r) => r.tw > 0 || r.lw > 0 || r.ly > 0);
  }, [selectedProducts, agg]);

  const wowProdTotals = useMemo(() => {
    const tw = wowProdRows.reduce((s, r) => s + r.tw, 0),
      lw = wowProdRows.reduce((s, r) => s + r.lw, 0),
      ly = wowProdRows.reduce((s, r) => s + r.ly, 0);
    return {
      product: 'TOTAL',
      tw,
      lw,
      ly,
      delta: tw - lw,
      pct: lw ? ((tw - lw) / lw) * 100 : null,
      yoy_delta: tw - ly,
      yoy_pct: ly ? ((tw - ly) / ly) * 100 : null,
    };
  }, [wowProdRows]);

  // ── WoW STORE ──
  const wowStoreRows = useMemo(() => {
    const storeSet = new Set(
      selectedStores.filter((s) => availableStores.includes(s))
    );
    const rows = [];
    storeSet.forEach((s) => {
      const dc = storeTodc[s];
      if (!dc || !selectedDCs.includes(dc)) return;
      const k = dc + '__' + s;
      const tw = Math.round((agg.store_tw[k] || 0) * 100) / 100;
      const lw = Math.round((agg.store_lw[k] || 0) * 100) / 100;
      const ly = Math.round((agg.store_ly[k] || 0) * 100) / 100;
      if (tw === 0 && lw === 0 && ly === 0) return;
      rows.push({
        _key: k,
        dc,
        store: s,
        tw,
        lw,
        ly,
        delta: tw - lw,
        pct: lw ? ((tw - lw) / lw) * 100 : null,
        yoy_delta: tw - ly,
        yoy_pct: ly ? ((tw - ly) / ly) * 100 : null,
      });
    });
    return rows;
  }, [selectedDCs, selectedStores, availableStores, agg, storeTodc]);

  const wowStoreTotals = useMemo(() => {
    const tw = wowStoreRows.reduce((s, r) => s + r.tw, 0),
      lw = wowStoreRows.reduce((s, r) => s + r.lw, 0),
      ly = wowStoreRows.reduce((s, r) => s + r.ly, 0);
    return {
      dc: 'TOTAL',
      store: '(' + wowStoreRows.length + ' stores)',
      tw,
      lw,
      ly,
      delta: tw - lw,
      pct: lw ? ((tw - lw) / lw) * 100 : null,
      yoy_delta: tw - ly,
      yoy_pct: ly ? ((tw - ly) / ly) * 100 : null,
    };
  }, [wowStoreRows]);

  // ── YTD DC ──
  const ytdDcRows = useMemo(
    () =>
      selectedDCs.map((dc) => {
        const v26 = agg.ytd_dc26[dc] || 0,
          v25 = agg.ytd_dc25[dc] || 0;
        return {
          _key: dc,
          dc,
          v26,
          v25,
          delta: v26 - v25,
          pct: v25 ? ((v26 - v25) / v25) * 100 : null,
        };
      }),
    [selectedDCs, agg]
  );

  const ytdDcTotals = useMemo(() => {
    const v26 = ytdDcRows.reduce((s, r) => s + r.v26, 0),
      v25 = ytdDcRows.reduce((s, r) => s + r.v25, 0);
    return {
      dc: 'TOTAL',
      v26,
      v25,
      delta: v26 - v25,
      pct: v25 ? ((v26 - v25) / v25) * 100 : null,
    };
  }, [ytdDcRows]);

  // ── YTD PRODUCT ──
  const ytdProdRows = useMemo(
    () =>
      selectedProducts
        .map((p) => {
          const v26 = agg.ytd_prod26[p] || 0,
            v25 = agg.ytd_prod25[p] || 0;
          return {
            _key: p,
            product: p,
            v26,
            v25,
            delta: v26 - v25,
            pct: v25 ? ((v26 - v25) / v25) * 100 : null,
          };
        })
        .filter((r) => r.v26 > 0 || r.v25 > 0),
    [selectedProducts, agg]
  );

  const ytdProdTotals = useMemo(() => {
    const v26 = ytdProdRows.reduce((s, r) => s + r.v26, 0),
      v25 = ytdProdRows.reduce((s, r) => s + r.v25, 0);
    return {
      product: 'TOTAL',
      v26,
      v25,
      delta: v26 - v25,
      pct: v25 ? ((v26 - v25) / v25) * 100 : null,
    };
  }, [ytdProdRows]);

  // ── YTD STORE ──
  const ytdStoreRows = useMemo(() => {
    const storeSet = new Set(
      selectedStores.filter((s) => availableStores.includes(s))
    );
    const rows = [];
    storeSet.forEach((s) => {
      const dc = storeTodc[s];
      if (!dc || !selectedDCs.includes(dc)) return;
      const k = dc + '__' + s;
      const v26 = agg.ytd_store26[k] || 0,
        v25 = agg.ytd_store25[k] || 0;
      if (v26 === 0 && v25 === 0) return;
      rows.push({
        _key: k,
        dc,
        store: s,
        v26,
        v25,
        delta: v26 - v25,
        pct: v25 ? ((v26 - v25) / v25) * 100 : null,
      });
    });
    return rows.sort((a, b) => b.v26 - a.v26);
  }, [selectedDCs, selectedStores, availableStores, agg, storeTodc]);

  const ytdStoreTotals = useMemo(() => {
    const v26 = ytdStoreRows.reduce((s, r) => s + r.v26, 0),
      v25 = ytdStoreRows.reduce((s, r) => s + r.v25, 0);
    return {
      dc: 'TOTAL',
      store: '(' + ytdStoreRows.length + ' stores)',
      v26,
      v25,
      delta: v26 - v25,
      pct: v25 ? ((v26 - v25) / v25) * 100 : null,
    };
  }, [ytdStoreRows]);

  // ── COLUMN DEFS ──
  const fwTW =
    selectedWeeks.length === 1
      ? 'FW' + String(selectedWeeks[0]).slice(-2)
      : 'FW' +
        String(Math.min(...selectedWeeks)).slice(-2) +
        '-' +
        String(Math.max(...selectedWeeks)).slice(-2);
  const fwLW = prevWeek ? 'FW' + String(prevWeek).slice(-2) : '—';
  const fwLY =
    selectedWeeks.length === 1
      ? 'FW' + String(selectedWeeks[0]).slice(-2) + '/25'
      : 'FW' +
        String(Math.min(...selectedWeeks)).slice(-2) +
        '-' +
        String(Math.max(...selectedWeeks)).slice(-2) +
        '/25';

  const wowCols = [
    { col: 'product', label: 'PRODUCT', type: 'label' },
    { col: 'lw', label: 'LW ' + fwLW, type: 'money', color: '#7a9ab0' },
    {
      col: 'tw',
      label: 'TW ' + fwTW,
      type: 'money',
      color: '#c8e8ff',
      bold: true,
    },
    { col: 'delta', label: '$ WoW', type: 'delta' },
    { col: 'pct', label: '% WoW', type: 'pct' },
    {
      col: 'ly',
      label: 'LY ' + fwLY,
      type: 'money',
      color: '#c8aaff',
      divider: true,
    },
    { col: 'yoy_delta', label: '$ YoY', type: 'delta' },
    { col: 'yoy_pct', label: '% YoY', type: 'pct' },
  ];
  const wowStoreCols = [
    { col: 'dc', label: 'DC', type: 'label', color: '#7acfff' },
    {
      col: 'store',
      label: 'STORE',
      type: 'label',
      color: '#e8f4ff',
      bold: true,
    },
    { col: 'lw', label: 'LW ' + fwLW, type: 'money', color: '#7a9ab0' },
    {
      col: 'tw',
      label: 'TW ' + fwTW,
      type: 'money',
      color: '#c8e8ff',
      bold: true,
    },
    { col: 'delta', label: '$ WoW', type: 'delta' },
    { col: 'pct', label: '% WoW', type: 'pct' },
    {
      col: 'ly',
      label: 'LY ' + fwLY,
      type: 'money',
      color: '#c8aaff',
      divider: true,
    },
    { col: 'yoy_delta', label: '$ YoY', type: 'delta' },
    { col: 'yoy_pct', label: '% YoY', type: 'pct' },
  ];
  const ytdBaseCols = [
    {
      col: 'v26',
      label: 'FY26 YTD',
      type: 'money',
      color: '#7acfff',
      bold: true,
    },
    {
      col: 'v25',
      label: 'FY25 YTD',
      type: 'money',
      color: '#c8aaff',
      divider: true,
    },
    { col: 'delta', label: '$ YoY', type: 'delta' },
    { col: 'pct', label: '% YoY', type: 'pct' },
  ];
  const ytdDcCols = [{ col: 'dc', label: 'DC', type: 'label' }, ...ytdBaseCols];
  const ytdProdCols = [
    { col: 'product', label: 'PRODUCT', type: 'label' },
    ...ytdBaseCols,
  ];
  const ytdStoreCols = [
    { col: 'dc', label: 'DC', type: 'label', color: '#7acfff' },
    {
      col: 'store',
      label: 'STORE',
      type: 'label',
      color: '#e8f4ff',
      bold: true,
    },
    ...ytdBaseCols,
  ];

  const wowKpis = [
    {
      label: 'THIS WEEK (FY26)',
      value: fmtMoney(wowProdTotals.tw),
      accent: '#7acfff',
    },
    {
      label: 'LAST WEEK (FY26)',
      value: fmtMoney(wowProdTotals.lw),
      accent: '#5a8aaa',
    },
    {
      label: 'WoW $',
      value: fmtDelta(wowProdTotals.delta),
      accent: deltaColor(wowProdTotals.delta),
    },
    {
      label: 'WoW %',
      value: fmtPct(wowProdTotals.pct),
      accent: deltaColor(wowProdTotals.pct),
    },
    {
      label: 'SAME WK LY (FY25)',
      value: fmtMoney(wowProdTotals.ly),
      accent: '#c8aaff',
      divider: true,
    },
    {
      label: 'YoY $',
      value: fmtDelta(wowProdTotals.yoy_delta),
      accent: deltaColor(wowProdTotals.yoy_delta),
    },
    {
      label: 'YoY %',
      value: fmtPct(wowProdTotals.yoy_pct),
      accent: deltaColor(wowProdTotals.yoy_pct),
    },
  ];
  const ytdKpis = [
    {
      label: 'FY26 YTD (FW01-10)',
      value: fmtMoney(ytdProdTotals.v26),
      accent: '#7acfff',
    },
    {
      label: 'FY25 YTD (FW01-10)',
      value: fmtMoney(ytdProdTotals.v25),
      accent: '#c8aaff',
    },
    {
      label: 'YTD $ Chg',
      value: fmtDelta(ytdProdTotals.delta),
      accent: deltaColor(ytdProdTotals.delta),
    },
    {
      label: 'YTD % Chg',
      value: fmtPct(ytdProdTotals.pct),
      accent: deltaColor(ytdProdTotals.pct),
    },
  ];

  const selStoreCount = selectedStores.filter((s) =>
    availableStores.includes(s)
  ).length;

  return (
    <div
      style={{
        background: '#060e17',
        minHeight: '100vh',
        fontFamily: "'DM Mono', monospace",
        color: '#c8d8e8',
      }}
    >
      {/* HEADER */}
      <div
        style={{
          borderBottom: '1px solid #1e3040',
          padding: '20px 28px',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
        }}
      >
        <div style={{ display: 'flex', alignItems: 'center', gap: 16 }}>
          <img
            src="data:image/png;base64,"
            alt="Sprouts"
            style={{ height: 44, width: 'auto', objectFit: 'contain' }}
          />
          <div>
            <div
              style={{
                fontSize: 10,
                letterSpacing: 3,
                color: '#3a6a8a',
                marginBottom: 4,
              }}
            >
              SALES ANALYTICS
            </div>
            <div
              style={{
                fontSize: 20,
                fontFamily: "'Space Grotesk', sans-serif",
                fontWeight: 700,
                color: '#e8f4ff',
              }}
            >
              {activeTab === 'wow'
                ? 'Week over Week Report'
                : 'FY2026 vs FY2025 Report'}
            </div>
          </div>
        </div>
        <div style={{ display: 'flex', gap: 8 }}>
          <button
            onClick={() => setActiveTab('wow')}
            style={{
              padding: '8px 22px',
              fontSize: 12,
              cursor: 'pointer',
              borderRadius: 6,
              fontFamily: "'DM Mono', monospace",
              letterSpacing: 1,
              background: activeTab === 'wow' ? '#1a4a6a' : '#0d1820',
              border:
                '1px solid ' + (activeTab === 'wow' ? '#3a8aca' : '#2a3a4a'),
              color: activeTab === 'wow' ? '#7acfff' : '#5a7a9a',
            }}
          >
            WoW + YoY
          </button>
          <button
            onClick={() => setActiveTab('ytd')}
            style={{
              padding: '8px 22px',
              fontSize: 12,
              cursor: 'pointer',
              borderRadius: 6,
              fontFamily: "'DM Mono', monospace",
              letterSpacing: 1,
              background: activeTab === 'ytd' ? '#1a4a6a' : '#0d1820',
              border:
                '1px solid ' + (activeTab === 'ytd' ? '#3a8aca' : '#2a3a4a'),
              color: activeTab === 'ytd' ? '#7acfff' : '#5a7a9a',
            }}
          >
            YTD
          </button>
        </div>
        <div style={{ textAlign: 'right' }}>
          <div style={{ fontSize: 9, color: '#3a6a8a', letterSpacing: 2 }}>
            SELECTED WEEK(S)
          </div>
          <div style={{ fontSize: 22, fontWeight: 500, color: '#7acfff' }}>
            {fwTW}
          </div>
          {prevWeek && (
            <div style={{ fontSize: 10, color: '#3a6a8a' }}>
              vs FW{String(prevWeek).slice(-2)} · LY {fwLY}
            </div>
          )}
        </div>
      </div>

      {/* FILTERS */}
      <div
        style={{
          padding: '12px 28px',
          display: 'flex',
          gap: 12,
          flexWrap: 'wrap',
          borderBottom: '1px solid #122030',
          alignItems: 'center',
          background: '#070d16',
        }}
      >
        <span style={{ fontSize: 10, color: '#3a6a8a', letterSpacing: 2 }}>
          WEEK
        </span>
        <div style={{ display: 'flex', gap: 2, flexWrap: 'wrap' }}>
          {ALL_WEEKS.map((w) => (
            <button
              key={w}
              onClick={() => toggleWeek(w)}
              style={{
                padding: '5px 9px',
                fontSize: 11,
                cursor: 'pointer',
                borderRadius: 4,
                fontFamily: "'DM Mono', monospace",
                background: selectedWeeks.includes(w) ? '#1a4a6a' : '#0f1923',
                border:
                  '1px solid ' +
                  (selectedWeeks.includes(w) ? '#3a8aca' : '#2a3a4a'),
                color: selectedWeeks.includes(w) ? '#7acfff' : '#7a9ab0',
              }}
            >
              {String(w).slice(-2)}
            </button>
          ))}
        </div>
        <div style={{ marginLeft: 'auto', display: 'flex', gap: 8 }}>
          <MultiSelect
            label="DC"
            options={ALL_DCS}
            selected={selectedDCs}
            onChange={handleDCChange}
          />
          <MultiSelect
            label="PRODUCT"
            options={ALL_PRODUCTS}
            selected={selectedProducts}
            onChange={setSelectedProducts}
          />
        </div>
      </div>

      {/* STORE PANEL */}
      <div
        style={{
          padding: '14px 28px',
          borderBottom: '1px solid #1e3040',
          background: '#08111a',
        }}
      >
        <div
          style={{
            fontSize: 9,
            color: '#3a6a8a',
            letterSpacing: 2,
            marginBottom: 10,
          }}
        >
          STORES — {availableStores.length} available · {selStoreCount} selected
        </div>
        <div style={{ display: 'flex', gap: 12, flexWrap: 'wrap' }}>
          {selectedDCs.map((dc) => {
            const dcStores = DC_STORES[dc] || [];
            const selInDC = selectedStores.filter((s) => dcStores.includes(s));
            const allInDC = selInDC.length === dcStores.length;
            return (
              <div
                key={dc}
                style={{
                  background: '#0d1820',
                  border: '1px solid #1e3040',
                  borderRadius: 8,
                  padding: '10px 14px',
                  minWidth: 220,
                  maxWidth: 300,
                }}
              >
                <div
                  style={{
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'space-between',
                    marginBottom: 8,
                  }}
                >
                  <span
                    style={{
                      fontSize: 10,
                      fontWeight: 500,
                      color: '#7acfff',
                      letterSpacing: 1,
                    }}
                  >
                    {dc}
                  </span>
                  <button
                    onClick={() => {
                      if (allInDC)
                        setSelectedStores((p) =>
                          p.filter((s) => !dcStores.includes(s))
                        );
                      else {
                        const ns = new Set([...selectedStores, ...dcStores]);
                        setSelectedStores([...ns].sort((a, b) => a - b));
                      }
                    }}
                    style={{
                      fontSize: 9,
                      padding: '2px 7px',
                      cursor: 'pointer',
                      borderRadius: 3,
                      background: allInDC ? '#1a4a6a' : '#141e2a',
                      border: '1px solid #2a4a6a',
                      color: '#7acfff',
                      fontFamily: "'DM Mono', monospace",
                    }}
                  >
                    {allInDC ? 'ALL ✓' : selInDC.length + '/' + dcStores.length}
                  </button>
                </div>
                <div
                  style={{
                    display: 'flex',
                    flexWrap: 'wrap',
                    gap: 3,
                    maxHeight: 100,
                    overflowY: 'auto',
                  }}
                >
                  {dcStores.map((s) => {
                    const on = selectedStores.includes(s);
                    return (
                      <button
                        key={s}
                        onClick={() =>
                          setSelectedStores((p) =>
                            on
                              ? p.filter((x) => x !== s)
                              : [...p, s].sort((a, b) => a - b)
                          )
                        }
                        style={{
                          padding: '2px 5px',
                          fontSize: 10,
                          cursor: 'pointer',
                          borderRadius: 3,
                          background: on ? '#1a3a5a' : '#0a1520',
                          border: '1px solid ' + (on ? '#3a7aaa' : '#1e2e3e'),
                          color: on ? '#9acfef' : '#4a6a8a',
                          fontFamily: "'DM Mono', monospace",
                        }}
                      >
                        {s}
                      </button>
                    );
                  })}
                </div>
                <div style={{ fontSize: 9, color: '#3a5a7a', marginTop: 6 }}>
                  {selInDC.length}/{dcStores.length} selected
                </div>
              </div>
            );
          })}
        </div>
      </div>

      {/* WoW TAB */}
      {activeTab === 'wow' && (
        <div>
          <div
            style={{
              display: 'flex',
              borderBottom: '1px solid #1e3040',
              overflowX: 'auto',
            }}
          >
            {wowKpis.map((k, i) => (
              <KpiTile
                key={i}
                label={k.label}
                value={k.value}
                accent={k.accent}
                divider={k.divider}
              />
            ))}
          </div>
          <SectionHeader
            title="By Product"
            sub="WoW · WEEKLY COMPARISON"
            badge={wowProdRows.length + ' products'}
          />
          <div style={{ paddingBottom: 8 }}>
            <DataTable
              cols={wowCols}
              rows={wowProdRows}
              totalsRow={wowProdTotals}
              defaultSort="tw"
              firstColLeft
            />
          </div>
          <div style={{ borderTop: '2px solid #1e3040', marginTop: 8 }}>
            <SectionHeader
              title="By Store"
              sub="WoW · STORE DRILL-DOWN"
              badge={wowStoreRows.length + ' stores'}
            />
            <div style={{ paddingBottom: 32 }}>
              <DataTable
                cols={wowStoreCols}
                rows={wowStoreRows}
                totalsRow={wowStoreTotals}
                defaultSort="tw"
                firstColLeft
              />
            </div>
          </div>
        </div>
      )}

      {/* YTD TAB */}
      {activeTab === 'ytd' && (
        <div>
          <div
            style={{
              display: 'flex',
              borderBottom: '1px solid #1e3040',
              overflowX: 'auto',
            }}
          >
            {ytdKpis.map((k, i) => (
              <KpiTile
                key={i}
                label={k.label}
                value={k.value}
                accent={k.accent}
              />
            ))}
          </div>
          <SectionHeader
            title="By DC"
            sub="YTD · FW01-FW10"
            badge={
              'FY26 ' +
              fmtMoney(ytdDcTotals.v26) +
              ' vs FY25 ' +
              fmtMoney(ytdDcTotals.v25)
            }
          />
          <div style={{ paddingBottom: 8 }}>
            <DataTable
              cols={ytdDcCols}
              rows={ytdDcRows}
              totalsRow={ytdDcTotals}
              defaultSort="v26"
              firstColLeft
            />
          </div>
          <div style={{ borderTop: '2px solid #1e3040', marginTop: 8 }}>
            <SectionHeader
              title="By Product"
              sub="YTD · FW01-FW10"
              badge={ytdProdRows.length + ' products'}
            />
            <div style={{ paddingBottom: 8 }}>
              <DataTable
                cols={ytdProdCols}
                rows={ytdProdRows}
                totalsRow={ytdProdTotals}
                defaultSort="v26"
                firstColLeft
              />
            </div>
          </div>
          <div style={{ borderTop: '2px solid #1e3040', marginTop: 8 }}>
            <SectionHeader
              title="By Store"
              sub="YTD · FW01-FW10"
              badge={ytdStoreRows.length + ' stores'}
            />
            <div style={{ paddingBottom: 40 }}>
              <DataTable
                cols={ytdStoreCols}
                rows={ytdStoreRows}
                totalsRow={ytdStoreTotals}
                defaultSort="v26"
                firstColLeft
              />
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
